-- MATEMATICAS (12)
-- =====================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('matematicas', 'bachillerato', '{2}', 'Series numéricas y convergencia', 'Una serie numérica es la suma formal de los infinitos términos de una sucesión. Aunque parezca paradójico, muchas sumas infinitas convergen a un valor finito cuando los términos decrecen lo bastante deprisa. La serie geométrica de razón r, con valor absoluto menor que uno, es el ejemplo clásico: su suma total es igual al primer término dividido por uno menos la razón. Este resultado sorprende a quien se enfrenta por primera vez al infinito matemático y ya fue tratado, con reservas filosóficas, por los griegos en las paradojas de Zenón.

Determinar si una serie converge requiere criterios específicos. El criterio del cociente compara términos consecutivos: si el límite del cociente es menor que uno, la serie converge. El criterio de la raíz procede de manera análoga con raíces enésimas. Para series alternadas, el criterio de Leibniz garantiza convergencia si los valores absolutos decrecen hacia cero. Los criterios de comparación con series conocidas, como la armónica o la p-ésima, aportan herramientas adicionales. Es fundamental distinguir convergencia absoluta de convergencia condicional, porque reordenar términos de una serie condicionalmente convergente puede alterar la suma.

Las series de potencias son centrales en el análisis moderno. Dentro de su radio de convergencia representan funciones mediante polinomios infinitos, lo que permite aproximar y calcular. Los desarrollos en serie de Taylor expresan funciones analíticas como suma infinita de términos construidos con sus derivadas en un punto. Aplicaciones prácticas incluyen cálculo numérico, resolución de ecuaciones diferenciales y teoría de la señal, donde las series de Fourier descomponen funciones periódicas en senos y cosenos con precisión controlable según el número de armónicos elegidos.',
'[{"pregunta":"Cuál es la suma de una serie geométrica con valor absoluto de r menor que 1?","opciones":["Primer término dividido por uno menos la razón","Siempre infinito","Cero","El producto de todos los términos"],"correcta":0},{"pregunta":"Qué garantiza el criterio del cociente?","opciones":["La divergencia siempre","Convergencia si el límite del cociente es menor que uno","Oscilación perpetua","Que los términos sean enteros"],"correcta":1},{"pregunta":"Qué diferencia convergencia absoluta de condicional?","opciones":["Son idénticas","Reordenar términos de una condicionalmente convergente puede alterar la suma","La absoluta no existe","La condicional siempre da cero"],"correcta":1},{"pregunta":"Qué descomponen las series de Fourier?","opciones":["Matrices cuadradas","Funciones periódicas en senos y cosenos","Ecuaciones lineales","Raíces cuadradas"],"correcta":1}]'::jsonb),

('matematicas', 'bachillerato', '{2}', 'Sucesiones y su convergencia', 'Una sucesión es una lista ordenada e infinita de números, donde cada elemento ocupa una posición natural. Estudiar su comportamiento a largo plazo equivale a analizar su límite cuando el índice tiende a infinito. Se dice que una sucesión converge a un número L si, fijada cualquier tolerancia arbitrariamente pequeña, a partir de cierto término todos los siguientes quedan dentro de ese margen. Si no se cumple esta condición, la sucesión diverge, bien a infinito, bien de forma oscilante sin aproximarse a un valor concreto.

Ciertos comportamientos generales facilitan el análisis. Las sucesiones monótonas y acotadas convergen siempre por el teorema de convergencia monótona. Las sucesiones de Cauchy, cuyos términos se aproximan indefinidamente entre sí, convergen en los números reales aunque no se conozca de antemano el límite. Este último concepto generaliza la idea de convergencia a espacios más abstractos y es esencial en la construcción rigurosa del análisis matemático moderno.

Entre las sucesiones célebres destaca la de Fibonacci, donde cada término es la suma de los dos anteriores, cuyo cociente entre consecutivos tiende a la razón áurea. El número e surge como límite de la expresión que relaciona cuotas de interés compuesto continuo cuando la frecuencia tiende a infinito. Las sucesiones recursivas, definidas mediante una fórmula que depende de términos anteriores, aparecen en modelos de población, algoritmos iterativos y análisis numérico. Comprender su convergencia permite anticipar el comportamiento de métodos como el de Newton, el de la bisección o el de las iteraciones de punto fijo en la práctica computacional cotidiana.',
'[{"pregunta":"Cuándo se dice que una sucesión converge a L?","opciones":["Cuando los términos oscilan sin límite","Cuando, fijada una tolerancia, todos los términos posteriores a cierto índice caen dentro de ella","Cuando todos los términos son iguales","Cuando los términos aumentan"],"correcta":1},{"pregunta":"Qué afirma el teorema de convergencia monótona?","opciones":["Las sucesiones monótonas y acotadas convergen","Ninguna sucesión monótona converge","Solo las decrecientes convergen","La monotonía impide convergencia"],"correcta":0},{"pregunta":"Qué es una sucesión de Cauchy?","opciones":["Una sucesión divergente","Aquella cuyos términos se aproximan indefinidamente entre sí","Una sucesión de enteros","Una fórmula cerrada"],"correcta":1},{"pregunta":"Qué relación tiene la sucesión de Fibonacci con la razón áurea?","opciones":["Ninguna","Los cocientes entre términos consecutivos tienden a la razón áurea","Multiplica sus términos por la razón áurea","Resta la razón áurea cada vez"],"correcta":1}]'::jsonb),

('matematicas', 'bachillerato', '{2}', 'Cónicas: propiedades y aplicaciones', 'Las cónicas son las curvas planas que se obtienen al cortar un cono circular recto con un plano. Según el ángulo del corte resultan circunferencias, elipses, parábolas o hipérbolas. También pueden definirse por propiedades geométricas relativas a puntos fijos llamados focos: la elipse es el lugar geométrico de los puntos cuya suma de distancias a dos focos es constante; la hipérbola, la diferencia de esas distancias; y la parábola, los puntos equidistantes de un foco y una directriz.

En coordenadas cartesianas, las cónicas centradas en el origen admiten ecuaciones muy características. La elipse tiene forma canónica con dos denominadores positivos; la hipérbola, con signos opuestos; y la parábola, con una sola coordenada elevada al cuadrado. Sus propiedades focales se traducen en reflexiones especiales: un rayo que parte de un foco de una elipse pasa tras reflejarse por el otro foco; en la parábola, cualquier rayo paralelo al eje se refleja pasando por el foco. Esta propiedad explica el funcionamiento de antenas parabólicas, reflectores de faros y espejos ustorios.

Las cónicas aparecen en la descripción del movimiento planetario. Johannes Kepler demostró que los planetas siguen órbitas elípticas con el Sol en uno de sus focos. Los cometas de periodo largo recorren trayectorias muy excéntricas, casi parabólicas. Los satélites artificiales y naves espaciales eligen cónicas para sus trayectorias según el régimen energético. En ingeniería se usan para diseñar puentes colgantes cuyas curvas aproximan parábolas y en óptica para corregir aberraciones esféricas mediante lentes con superficies conicoidales precisas muy complejas.',
'[{"pregunta":"Cómo se define una parábola geométricamente?","opciones":["Puntos con suma constante a dos focos","Puntos equidistantes de un foco y una directriz","Puntos con producto constante","Puntos aleatorios"],"correcta":1},{"pregunta":"Qué propiedad reflectante tiene la parábola?","opciones":["Refleja rayos perpendiculares al suelo","Un rayo paralelo al eje se refleja pasando por el foco","Absorbe toda la luz","Refleja hacia el infinito"],"correcta":1},{"pregunta":"Qué forma tienen las órbitas planetarias según Kepler?","opciones":["Circulares","Elipses con el Sol en un foco","Parábolas cerradas","Triángulos"],"correcta":1},{"pregunta":"Qué aplicación de ingeniería menciona el texto?","opciones":["Puentes colgantes con curvas que aproximan parábolas","Estaciones marítimas","Balizas acústicas","Cintas transportadoras"],"correcta":0}]'::jsonb),

('matematicas', 'bachillerato', '{2}', 'Introducción a los sistemas dinámicos', 'Un sistema dinámico describe la evolución de un estado a lo largo del tiempo mediante una regla determinista. Puede ser discreto, si el tiempo avanza por pasos, o continuo, si se describe con ecuaciones diferenciales. El espacio de fases contiene todos los estados posibles, y la trayectoria que sigue el sistema aparece como una curva o una sucesión en ese espacio. Esta formulación, heredada de la mecánica clásica, se aplica hoy en ecología, economía, biología, climatología y muchas otras disciplinas.

Los estados en los que el sistema permanece sin cambios se llaman puntos fijos o estacionarios. Su estabilidad se estudia analizando cómo se comportan pequeñas perturbaciones en torno a ellos. Un punto fijo estable atrae las trayectorias cercanas, uno inestable las repele. Otros comportamientos característicos son los ciclos límite, oscilaciones periódicas a las que convergen las trayectorias vecinas, y los atractores extraños, patrones geométricos fractales hacia los que tienden los sistemas caóticos.

El caos determinista es uno de los hallazgos más sorprendentes del siglo XX. Sistemas descritos por ecuaciones sencillas, como el modelo logístico de poblaciones o las ecuaciones de Lorenz para la convección atmosférica, generan trayectorias impredecibles a largo plazo porque dependen de manera extremadamente sensible de las condiciones iniciales. El llamado efecto mariposa resume poéticamente esta idea. Aun siendo deterministas, los sistemas caóticos solo se pueden predecir estadísticamente, lo que explica las limitaciones fundamentales de la predicción meteorológica más allá de unos pocos días con precisión aceptable.',
'[{"pregunta":"Qué es un punto fijo estable?","opciones":["Un punto que repele trayectorias","Un estado que atrae trayectorias cercanas","Un estado inexistente","Una trayectoria cerrada"],"correcta":1},{"pregunta":"Qué es un atractor extraño?","opciones":["Un patrón fractal hacia el que tienden sistemas caóticos","Un punto sin estabilidad","Una trayectoria periódica","Una fuerza gravitatoria"],"correcta":0},{"pregunta":"Qué caracteriza al caos determinista?","opciones":["Ecuaciones aleatorias","Sensibilidad extrema a las condiciones iniciales","Imposibilidad de escribir ecuaciones","Energía infinita"],"correcta":1},{"pregunta":"Qué limitación práctica se deduce del caos?","opciones":["Imposibilidad de predecir el tiempo más allá de unos pocos días","Imposibilidad de escribir fórmulas","Imposibilidad de sumar fracciones","Imposibilidad de viajar"],"correcta":0}]'::jsonb),

('matematicas', 'bachillerato', '{2}', 'Ecuaciones diferenciales elementales', 'Una ecuación diferencial relaciona una función desconocida con sus derivadas. Buena parte de las leyes físicas se expresan de este modo: la segunda ley de Newton, por ejemplo, vincula la aceleración, que es la segunda derivada de la posición, con la fuerza aplicada. Resolver una ecuación diferencial significa encontrar todas las funciones que la satisfacen, casi siempre a través de una familia con constantes arbitrarias que se determinan mediante condiciones iniciales o de contorno.

Las ecuaciones diferenciales ordinarias de primer orden abordables a nivel elemental incluyen las de variables separables, donde los términos con la variable independiente y los de la función incógnita se agrupan en miembros distintos y se integran por separado. Las ecuaciones lineales, de la forma y prima más p de x por y igual a q de x, se resuelven mediante un factor integrante calculado a partir del coeficiente p. Los modelos de crecimiento exponencial, desintegración radiactiva, enfriamiento de Newton o caída con resistencia aerodinámica responden a estas ecuaciones elementales.

Las ecuaciones lineales de segundo orden con coeficientes constantes describen osciladores armónicos amortiguados y circuitos eléctricos RLC. Su solución depende de las raíces de una ecuación característica: reales distintas, reales dobles o complejas conjugadas, cada una con un comportamiento cualitativo distinto (sobreamortiguado, críticamente amortiguado u oscilación amortiguada). Cuando la solución analítica no es posible se recurre a métodos numéricos como Euler o Runge-Kutta, fundamentales en simulación de sistemas físicos, ingeniería química, meteorología, economía y control de procesos industriales complejos de todo tipo.',
'[{"pregunta":"Qué relaciona una ecuación diferencial?","opciones":["Una función con sus derivadas","Números enteros","Matrices","Vectores ortogonales"],"correcta":0},{"pregunta":"Cómo se resuelve una ecuación lineal de primer orden?","opciones":["Mediante un factor integrante","Por suma directa","Con el teorema de Pitágoras","Derivando tres veces"],"correcta":0},{"pregunta":"Qué comportamientos tiene una ecuación de segundo orden con coeficientes constantes?","opciones":["Sobreamortiguado, críticamente amortiguado u oscilación amortiguada","Solo exponencial creciente","Siempre constante","Únicamente lineal"],"correcta":0},{"pregunta":"Qué métodos numéricos se citan?","opciones":["Euler y Runge-Kutta","Gauss y Laplace","Fermat y Pascal","Bolzano y Weierstrass"],"correcta":0}]'::jsonb),

('matematicas', 'bachillerato', '{2}', 'Espacios vectoriales y bases', 'Un espacio vectorial es una estructura algebraica formada por un conjunto de objetos, llamados vectores, sobre los que se definen dos operaciones: una suma interna y un producto por escalares, procedentes de un cuerpo como el de los reales o los complejos. Estas operaciones deben cumplir una serie de propiedades razonables (conmutativa, asociativa, existencia de elemento neutro, opuesto, distributivas) que convierten el conjunto en un terreno apto para manipular combinaciones lineales con plena generalidad.

La noción de base es una de las más fértiles de esta estructura. Una base es un conjunto de vectores linealmente independientes que generan todo el espacio mediante combinaciones lineales únicas. El número de elementos de una base se llama dimensión y es una propiedad intrínseca del espacio: independiente de la base concreta elegida. En el espacio ordinario tridimensional, la dimensión es tres; en el plano, dos; y hay espacios infinito-dimensionales, como los de funciones, donde la base debe entenderse en un sentido generalizado.

Las aplicaciones lineales son funciones entre espacios vectoriales que respetan la suma y el producto por escalares. Quedan completamente determinadas por la imagen de una base. Al elegir bases en los espacios de partida y llegada, la aplicación se representa mediante una matriz cuyas columnas son las imágenes de los vectores base. Los conceptos de núcleo, imagen, rango y nulidad permiten clasificar las aplicaciones y abordan la resolución de sistemas lineales. Esta maquinaria es esencial en cristalografía, procesamiento de señales, economía, aprendizaje automático y computación gráfica del mundo moderno actual.',
'[{"pregunta":"Qué es una base de un espacio vectorial?","opciones":["Un único vector","Un conjunto de vectores linealmente independientes que generan el espacio","Todos los vectores del plano","Una matriz fija"],"correcta":1},{"pregunta":"Qué es la dimensión?","opciones":["El tamaño del vector","El número de elementos de cualquier base del espacio","La norma de un vector","El determinante de una matriz"],"correcta":1},{"pregunta":"Cómo se representa una aplicación lineal?","opciones":["Mediante una matriz cuyas columnas son imágenes de los vectores base","Como un número real","Como un polinomio de grado 2","Solo gráficamente"],"correcta":0},{"pregunta":"Dónde se aplican estas ideas?","opciones":["Procesamiento de señales y aprendizaje automático","Solo en geometría elemental","Únicamente en botánica","Únicamente en música"],"correcta":0}]'::jsonb),

('matematicas', 'bachillerato', '{2}', 'Distribución de Poisson', 'La distribución de Poisson describe la probabilidad de que ocurra un número determinado de sucesos en un intervalo fijo de tiempo o espacio, cuando esos sucesos son independientes entre sí y suceden con una tasa media constante. Se utiliza para modelar llamadas a una centralita, partículas radiactivas detectadas por unidad de tiempo, errores tipográficos por página, accidentes en un cruce, clientes en una cola o mutaciones por generación.

La probabilidad de obtener exactamente k sucesos cuando el valor medio esperado es lambda viene dada por la fórmula e elevado a menos lambda multiplicado por lambda a la k y dividido entre k factorial. La media y la varianza de la distribución coinciden y son iguales a lambda, una característica distintiva entre las distribuciones discretas. La distribución es límite de una binomial cuando el número de ensayos tiende a infinito y la probabilidad de éxito tiende a cero, manteniendo su producto constante.

Su uso práctico exige que se cumplan ciertas hipótesis: independencia entre sucesos, estacionariedad del proceso y ausencia de eventos simultáneos exactos. Cuando el fenómeno real se aparta de estas condiciones se recurre a generalizaciones como la binomial negativa o los procesos de Poisson no homogéneos. En física se aplica a la cuenta de partículas en detectores, en biología a recuentos de bacterias en cultivos, en finanzas a la frecuencia de eventos raros, y en logística a la programación de recursos en servicios de urgencia, calidad industrial y modelos actuales de teoría de colas donde el sistema recibe eventos aleatorios con alta frecuencia.',
'[{"pregunta":"Qué modela la distribución de Poisson?","opciones":["La media aritmética de varios datos","Número de sucesos independientes con tasa media constante","Diferencia entre dos poblaciones","Pendiente de una recta"],"correcta":1},{"pregunta":"Qué relación hay entre media y varianza en Poisson?","opciones":["La varianza es el doble","Coinciden y son iguales a lambda","No están relacionadas","La media es cero"],"correcta":1},{"pregunta":"De qué distribución es límite la de Poisson?","opciones":["De la binomial cuando n tiende a infinito y p a cero","De la normal","De la exponencial","De la geométrica"],"correcta":0},{"pregunta":"Qué hipótesis debe cumplir el fenómeno?","opciones":["Independencia, estacionariedad y ausencia de eventos simultáneos","Dependencia total","Eventos simultáneos abundantes","Media cero"],"correcta":0}]'::jsonb),

('matematicas', 'bachillerato', '{2}', 'Regresión lineal', 'La regresión lineal es una técnica estadística que busca modelar la relación entre una variable dependiente y una o más variables independientes mediante una función lineal. En el caso más sencillo, la regresión simple ajusta una recta de ecuación y igual a a por x más b a una nube de puntos bidimensional, de modo que la suma de los cuadrados de las distancias verticales entre los puntos y la recta sea mínima. Este es el método de mínimos cuadrados, formulado por Legendre y Gauss a principios del siglo XIX.

Los coeficientes de la recta se interpretan con facilidad: la pendiente indica el cambio esperado en la variable dependiente por cada unidad de aumento de la independiente; la ordenada en el origen aporta el valor predicho cuando la variable independiente es cero. El coeficiente de correlación mide la fuerza y el signo de la asociación lineal, y su cuadrado, denominado coeficiente de determinación, cuantifica la proporción de variabilidad explicada por el modelo. Valores cercanos a 1 indican un ajuste excelente; cercanos a 0, relación lineal inexistente.

La regresión lineal múltiple generaliza el planteamiento a varias variables independientes y se expresa matricialmente con soluciones explícitas siempre que la matriz de diseño tenga rango completo. Supuestos habituales incluyen linealidad, normalidad de los residuos, homoscedasticidad e independencia. Cuando se violan, se emplean transformaciones, regresión robusta o métodos no lineales. La regresión sirve para predecir, interpretar relaciones y elaborar modelos causales sencillos en economía, biología, ciencias sociales, ingeniería, medicina y también, con precauciones, en análisis cotidiano de datos masivos por aprendizaje automático.',
'[{"pregunta":"Qué minimiza el método de mínimos cuadrados?","opciones":["La suma de los residuos","La suma de los cuadrados de las distancias verticales a la recta","El máximo de los residuos","El producto de las distancias"],"correcta":1},{"pregunta":"Qué indica el coeficiente de determinación?","opciones":["La varianza total","La proporción de variabilidad explicada por el modelo","La media de las variables","La pendiente de la recta"],"correcta":1},{"pregunta":"Qué supuesto se cita sobre los residuos?","opciones":["Que sean idénticos","Normalidad, independencia y homoscedasticidad","Que no existan","Que crezcan siempre"],"correcta":1},{"pregunta":"Qué generalización se menciona?","opciones":["La regresión lineal múltiple con varias variables independientes","La regresión sin variables","El producto cartesiano","La división euclídea"],"correcta":0}]'::jsonb),

('matematicas', 'bachillerato', '{2}', 'Geometría proyectiva', 'La geometría proyectiva nace del estudio de las proyecciones y las reglas de la perspectiva pictórica renacentista. A diferencia de la geometría euclídea, donde las rectas paralelas no se encuentran, la proyectiva considera que todas las rectas paralelas concurren en un punto idealizado del infinito. Esta generalización elimina casos particulares y aporta una elegancia nueva: los conceptos de paralelismo y perpendicularidad dejan de ser fundamentales, y toda la geometría se reduce a relaciones de incidencia entre puntos y rectas.

Dos de los teoremas más célebres ilustran su poder. El teorema de Pappus afirma que, dados dos grupos de tres puntos colineales, los tres puntos obtenidos como intersección de ciertas rectas resultan también colineales. El teorema de Desargues establece la concurrencia de tres puntos cuando dos triángulos se corresponden por una proyección central. Ambos resultados admiten enunciados simétricos en los que los papeles de punto y recta son intercambiables, y esa dualidad entre puntos y rectas constituye una característica propia de la disciplina.

En coordenadas, la geometría proyectiva utiliza coordenadas homogéneas: cada punto del plano proyectivo se representa por una terna de números, excluido el cero, y dos ternas proporcionales describen el mismo punto. Este formalismo es la base de la informática gráfica moderna. Las transformaciones proyectivas, descritas por matrices invertibles, explican cómo un objeto tridimensional se proyecta en una pantalla y permiten manipular imágenes con homografías útiles en fotografía computacional, visión por ordenador y realidad aumentada aplicadas al cine y los videojuegos.',
'[{"pregunta":"Qué diferencia esencial tiene con la geometría euclídea?","opciones":["Considera que las paralelas se encuentran en el infinito","Niega el concepto de punto","Utiliza solo números enteros","No admite rectas"],"correcta":0},{"pregunta":"Qué afirma el teorema de Desargues?","opciones":["Que los triángulos son congruentes","La concurrencia de ciertos puntos cuando dos triángulos se corresponden por proyección central","Que las rectas se cruzan a 90 grados","Que el área se duplica"],"correcta":1},{"pregunta":"Qué dualidad característica posee la proyectiva?","opciones":["Entre puntos y rectas","Entre áreas y volúmenes","Entre ángulos y longitudes","Entre cuerpos y superficies"],"correcta":0},{"pregunta":"Dónde se aplica el formalismo de coordenadas homogéneas?","opciones":["En informática gráfica y visión por ordenador","Solo en geometría pura","En aritmética básica","En recetas de cocina"],"correcta":0}]'::jsonb),

('matematicas', 'bachillerato', '{2}', 'Cálculo de variaciones', 'El cálculo de variaciones es la rama del análisis matemático que se ocupa de encontrar funciones que hacen máximo o mínimo un cierto funcional, es decir, una regla que asigna un número real a cada función candidata. El problema más famoso es el de la braquistócrona: dados dos puntos a distinta altura, determinar la curva por la que un cuerpo, partiendo del reposo y bajo la gravedad, desciende en el menor tiempo posible. Johann Bernoulli lo planteó en 1696 como un desafío que atrajo a los mayores matemáticos de la época.

La herramienta fundamental es la ecuación de Euler-Lagrange, deducida por Leonhard Euler y refinada por Joseph-Louis Lagrange. Condición necesaria que toda solución del problema variacional debe cumplir, convierte el problema original en una ecuación diferencial ordinaria o parcial. Las condiciones de contorno del problema aportan los datos que fijan la solución entre la familia general. El principio de Fermat en óptica, según el cual la luz elige el camino de tiempo estacionario, fue uno de los primeros ejemplos históricos.

El cálculo de variaciones es la base del principio de mínima acción en física, formulado por Maupertuis y extendido por Hamilton: la trayectoria que describe un sistema mecánico extremiza la integral de una función lagrangiana. Este marco conduce a las ecuaciones de movimiento de la mecánica clásica, relativista y cuántica. En ingeniería se aplica al diseño óptimo de estructuras, al control automático y a la robótica. En economía, el cálculo variacional guía la toma de decisiones dinámicas y los modelos de crecimiento con horizonte temporal infinito característicos.',
'[{"pregunta":"Qué es la braquistócrona?","opciones":["Un polígono regular","La curva de descenso más rápido entre dos puntos bajo gravedad","Una figura con tres lados","Una función logarítmica"],"correcta":1},{"pregunta":"Qué herramienta fundamental utiliza el cálculo de variaciones?","opciones":["La ecuación de Euler-Lagrange","El teorema de Thales","El teorema del binomio","La regla de Cramer"],"correcta":0},{"pregunta":"Qué principio físico surge del cálculo de variaciones?","opciones":["Principio de mínima acción","Principio de Arquímedes","Principio de Pascal","Principio de incertidumbre"],"correcta":0},{"pregunta":"Qué ejemplo histórico inicial cita el texto?","opciones":["El principio de Fermat en óptica","El teorema de Tales","La conjetura de Goldbach","El último teorema de Fermat"],"correcta":0}]'::jsonb),

('matematicas', 'bachillerato', '{2}', 'Teoría de grafos', 'Un grafo es un objeto matemático compuesto por un conjunto de vértices y un conjunto de aristas que unen pares de ellos. Esta estructura sencilla permite modelar relaciones muy variadas: rutas entre ciudades, contactos sociales, enlaces web, circuitos electrónicos, reacciones químicas o dependencias entre tareas. Leonhard Euler inauguró la disciplina en 1736 al resolver el problema de los puentes de Königsberg, preguntando si se podía recorrer los siete puentes de la ciudad pasando por cada uno exactamente una vez.

Los conceptos básicos incluyen el grado de un vértice, número de aristas que inciden en él; camino, sucesión de vértices conectados por aristas; y conectividad, que indica si todos los vértices son alcanzables entre sí. Un árbol es un grafo conexo sin ciclos, muy útil para representar jerarquías y algoritmos recursivos. Un grafo bipartito divide sus vértices en dos conjuntos disjuntos con todas las aristas entre ellos, estructura fundamental en problemas de emparejamiento óptimo.

Los algoritmos sobre grafos han transformado la informática. El algoritmo de Dijkstra calcula caminos mínimos entre vértices ponderados. El de Kruskal construye árboles de expansión de coste mínimo. La búsqueda en anchura y la búsqueda en profundidad recorren el grafo de manera sistemática y permiten detectar ciclos, componentes conexas y rutas. Problemas como el del viajante o la coloración de grafos, fáciles de enunciar pero difíciles de resolver, motivaron el nacimiento de la teoría de la complejidad computacional, base intelectual de aplicaciones actuales como navegación GPS, redes sociales, planificación logística y bioinformática molecular.',
'[{"pregunta":"Cuándo nació la teoría de grafos?","opciones":["En 1736 con el problema de los puentes de Königsberg","En el siglo XXI","En la antigua Grecia","En la Edad Media temprana"],"correcta":0},{"pregunta":"Qué es un árbol en teoría de grafos?","opciones":["Un grafo con bucles múltiples","Un grafo conexo sin ciclos","Un grafo vacío","Un grafo completo"],"correcta":1},{"pregunta":"Qué calcula el algoritmo de Dijkstra?","opciones":["Caminos mínimos entre vértices ponderados","Áreas de polígonos","Integrales definidas","La serie armónica"],"correcta":0},{"pregunta":"Qué teoría surgió a partir de problemas como el del viajante?","opciones":["Teoría de conjuntos","Teoría de la complejidad computacional","Geometría elemental","Teoría analítica de números"],"correcta":1}]'::jsonb),

('matematicas', 'bachillerato', '{2}', 'Criptografía matemática', 'La criptografía moderna se apoya en resultados profundos de la teoría de números y el álgebra abstracta para garantizar la confidencialidad, la integridad y la autenticidad de las comunicaciones digitales. A diferencia de los cifrados clásicos por sustitución o transposición, los algoritmos contemporáneos se basan en problemas matemáticos cuya dificultad computacional protege los mensajes incluso si el adversario conoce el procedimiento de cifrado. El principio de Kerckhoffs, formulado en el siglo XIX, ya sostenía que la seguridad no debe depender del secreto del algoritmo sino del de la clave.

El cifrado RSA, propuesto en 1977 por Rivest, Shamir y Adleman, ilustra la potencia de este enfoque. Se eligen dos números primos muy grandes, se calcula su producto y se generan claves pública y privada usando el teorema de Euler y la aritmética modular. Cualquiera puede cifrar un mensaje con la clave pública del destinatario, pero solo quien posee la clave privada asociada puede descifrarlo. Romper RSA exige factorizar el producto, tarea aún intratable para los ordenadores clásicos cuando los primos son del orden de miles de cifras decimales.

Las curvas elípticas ofrecen una alternativa que requiere claves más cortas con seguridad equivalente, y son la base de protocolos usados en billeteras de criptomonedas y en comunicaciones móviles. La llegada futura de computadoras cuánticas obligaría a sustituir RSA y curvas elípticas por criptografía postcuántica, basada en redes euclídeas, funciones hash o códigos correctores, campos intensamente investigados. El estándar actual combina varias técnicas para garantizar confidencialidad, integridad y autenticidad en la vida digital cotidiana masiva global.',
'[{"pregunta":"Qué establece el principio de Kerckhoffs?","opciones":["La seguridad depende del secreto de la clave, no del algoritmo","Los algoritmos deben ser siempre secretos","Las claves son innecesarias","Solo se deben usar cifrados simples"],"correcta":0},{"pregunta":"En qué problema matemático se basa RSA?","opciones":["En la factorización de un producto de primos grandes","En la suma de fracciones","En integrar polinomios","En la raíz cuadrada"],"correcta":0},{"pregunta":"Qué ventaja ofrecen las curvas elípticas?","opciones":["Requieren claves más cortas con seguridad equivalente","Son siempre inseguras","No tienen aplicación","Exigen más cálculos que RSA siempre"],"correcta":0},{"pregunta":"Qué es la criptografía postcuántica?","opciones":["Una técnica inútil","Criptografía resistente a ordenadores cuánticos basada en redes, hash y códigos","Una forma de computación clásica","Un lenguaje de programación"],"correcta":1}]'::jsonb);

-- =====================================================
-- DIBUJO TECNICO (12)
-- =====================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('dibujo-tecnico', 'bachillerato', '{2}', 'Vistas auxiliares', 'Las vistas auxiliares son proyecciones ortogonales obtenidas sobre planos inclinados respecto a los planos principales del sistema diédrico. Se emplean cuando una pieza presenta caras oblicuas cuyas verdaderas dimensiones no aparecen en las vistas habituales, alzado, planta y perfil. Al proyectar sobre un plano paralelo a esa cara inclinada, el dibujante obtiene su forma real y puede acotarla con precisión sin introducir deformaciones que compliquen la lectura del plano.

Para construir una vista auxiliar de primera generación se elige un plano de proyección paralelo a la cara oblicua y perpendicular a uno de los planos principales. Los puntos de la pieza se trasladan siguiendo líneas perpendiculares al nuevo plano y conservando las distancias tomadas en las vistas ortogonales de partida. Cuando la cara es doblemente inclinada, como en un tejado con pendientes en dos direcciones, se requiere una segunda vista auxiliar, obtenida a su vez sobre un plano ortogonal a la primera.

Las vistas auxiliares resultan imprescindibles en la fabricación mecánica, la carpintería metálica, la arquitectura y el diseño de tolvas, conductos o cubiertas inclinadas. Permiten mostrar agujeros, ranuras y detalles que de otro modo se representarían deformados. Suelen dibujarse junto a la vista principal con una indicación de dirección de observación mediante una flecha y una letra mayúscula. Las normas UNE y la norma ISO establecen cómo colocar estas vistas en el plano, cómo acotarlas y cómo se deben relacionar con el resto de proyecciones del conjunto para evitar ambigüedades interpretativas.',
'[{"pregunta":"Para qué sirven las vistas auxiliares?","opciones":["Para dibujar solo la planta","Para mostrar caras oblicuas en su verdadera magnitud","Para sustituir la sección completa","Para acotar ángulos agudos siempre"],"correcta":1},{"pregunta":"Cómo se elige el plano de proyección auxiliar de primera generación?","opciones":["Paralelo a la cara oblicua y perpendicular a un plano principal","Siempre horizontal","Siempre a 45 grados","Paralelo al plano de planta"],"correcta":0},{"pregunta":"Qué ocurre con caras doblemente inclinadas?","opciones":["Nunca se representan","Se requiere una segunda vista auxiliar ortogonal a la primera","Se giran 90 grados","Se representan solo en perspectiva"],"correcta":1},{"pregunta":"Qué normas regulan la disposición de vistas auxiliares?","opciones":["UNE e ISO","Únicamente DIN","Solo ASTM","Ninguna en absoluto"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Enlaces múltiples y tangencias', 'Los enlaces son construcciones geométricas que permiten unir dos líneas, una recta y una curva o dos curvas, de tal forma que exista continuidad sin aristas ni cambios bruscos de dirección. Para ello, el punto común tiene que ser punto de tangencia, de modo que las dos líneas compartan la misma tangente. En dibujo técnico estos enlaces aparecen en carrocerías, mangos de herramientas, logotipos, moldes industriales y cualquier diseño donde la apariencia fluida y la seguridad en el uso sean relevantes.

El enlace más sencillo es el de dos rectas mediante un arco de radio dado. Se trazan paralelas a las rectas originales a una distancia igual al radio y se halla su intersección, que será el centro del arco. Los pies de las perpendiculares bajadas desde ese centro sobre las rectas son los puntos de tangencia. Cuando se trata de enlazar rectas con circunferencias o dos circunferencias entre sí, se aplican los principios de tangencia interior y exterior: el centro del arco de enlace debe situarse a distancias adecuadas respecto de los centros de las curvas implicadas.

Los enlaces múltiples encadenan varios de estos arcos para obtener perfiles complejos. El diseño de las letras de un tipo tipográfico, la forma de un álabe de turbina o el contorno de un asa de puerta son ejemplos característicos. La precisión de las tangencias es crucial: una transición mal resuelta genera puntos angulosos difíciles de mecanizar. Hoy, los programas de CAD calculan automáticamente puntos y centros de tangencia mediante construcciones internas basadas en estas reglas geométricas tradicionales del dibujo a mano alzada y con instrumentos clásicos.',
'[{"pregunta":"Qué condición geométrica define un enlace?","opciones":["Que las líneas formen un ángulo recto","Que el punto común sea de tangencia con tangente compartida","Que se corten en dos puntos","Que sean perpendiculares"],"correcta":1},{"pregunta":"Cómo se halla el centro del arco de enlace entre dos rectas?","opciones":["Prolongando las rectas","Como intersección de paralelas trazadas a distancia igual al radio","En el punto medio de ambas rectas","Siempre en el origen"],"correcta":1},{"pregunta":"Qué principios se aplican al enlazar circunferencias?","opciones":["Tangencia interior y exterior","Paralelismo forzado","Simetría especular","Homotecia negativa"],"correcta":0},{"pregunta":"Qué riesgo tiene una transición mal resuelta?","opciones":["Puntos angulosos difíciles de mecanizar","Generar simetrías perfectas","Reducir costes automáticos","Eliminar todos los radios"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Superficies regladas', 'Una superficie reglada es aquella que puede generarse mediante el movimiento de una recta, llamada generatriz, a lo largo del espacio siguiendo una trayectoria determinada. Por cada punto de la superficie pasa al menos una recta contenida completamente en ella. Esta propiedad hace que estas superficies sean especialmente interesantes para la ingeniería, porque admiten construcciones con cables, tablillas o chapas planas, lo que abarata su fabricación y permite formas sorprendentemente complejas a partir de piezas rectas.

Las superficies regladas se dividen en desarrollables y alabeadas. Las desarrollables son aquellas que pueden extenderse sobre un plano sin deformación, como el cono o el cilindro: basta con cortar a lo largo de una generatriz y abrir la superficie hasta aplanarla. Las alabeadas, como el hiperboloide de una hoja o el paraboloide hiperbólico, contienen rectas pero no pueden desplegarse sobre un plano sin estirarse o romperse. En arquitectura, el empleo de superficies alabeadas da lugar a formas espectaculares: cubiertas de estadios, pabellones de exposición y torres de refrigeración en centrales térmicas.

El trabajo gráfico con estas superficies exige dominar la construcción de sus trazas sobre los planos de proyección, la identificación de sus generatrices rectilíneas y la obtención de secciones planas. En el diseño industrial se usan para conducciones con cambios de dirección progresivos o para álabes de turbinas, ventiladores y hélices. Los programas de CAD permiten modelar superficies regladas complejas mediante algoritmos que interpolan entre curvas directrices y visualizan el resultado tridimensional con alta fidelidad y precisión métrica para calibraciones en la práctica industrial más exigente.',
'[{"pregunta":"Qué es una superficie reglada?","opciones":["La que se genera por movimiento de una recta generatriz","La que se construye con triángulos","Un tipo de sólido platónico","Una curva plana"],"correcta":0},{"pregunta":"Qué distingue a una superficie desarrollable?","opciones":["Puede extenderse sobre un plano sin deformación","Contiene solo curvas","Es siempre esférica","Tiene volumen mínimo"],"correcta":0},{"pregunta":"Qué ejemplo de superficie alabeada se cita?","opciones":["El cilindro","El paraboloide hiperbólico","El cono truncado","El plano inclinado"],"correcta":1},{"pregunta":"Qué ventaja industrial ofrecen las regladas?","opciones":["Se pueden construir con cables, tablillas o chapas","Requieren siempre materiales flexibles","Solo se fabrican en papel","No admiten acabados"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Perspectiva isométrica avanzada', 'La perspectiva isométrica es una representación axonométrica en la que los tres ejes coordinados forman entre sí ángulos iguales de 120 grados al proyectarse sobre el plano del dibujo. Los coeficientes de reducción son idénticos para los tres ejes, lo que facilita enormemente los cálculos y las construcciones. Por convenio, las medidas se toman directamente sobre los ejes sin aplicar la reducción teórica, aunque esto produzca una ligera ampliación respecto a la proyección ortogonal original.

En sus niveles avanzados, la isométrica permite representar formas complejas que incluyen circunferencias y curvas. Una circunferencia contenida en un plano coordinado se proyecta como una elipse cuyos ejes mayor y menor se determinan a partir de la dirección de las generatrices. Para trazarla a mano suele recurrirse a óvalos isométricos aproximados formados por cuatro arcos de circunferencia, con centros en las esquinas del rombo envolvente. Este procedimiento agiliza el dibujo sin perder precisión aceptable para la mayoría de los planos industriales de uso común.

Las piezas con taladros inclinados, superficies curvas tangentes o roscas helicoidales plantean desafíos adicionales que exigen una cuidadosa selección de planos de construcción auxiliares. La isométrica avanzada se utiliza en catálogos industriales, manuales de instrucciones y presentaciones donde es necesario que una única imagen muestre con claridad las tres dimensiones del objeto. Aunque los programas CAD generan automáticamente estas vistas a partir del modelo tridimensional, conocer los fundamentos manuales permite interpretar y corregir cualquier proyección con criterio técnico sólido y hacer que el documento final sea perfectamente fiable para la fábrica.',
'[{"pregunta":"Qué ángulos forman los ejes en perspectiva isométrica?","opciones":["90 grados","120 grados iguales","60 grados","45 grados"],"correcta":1},{"pregunta":"Qué ocurre al proyectar una circunferencia en isométrica?","opciones":["Se convierte en una elipse","Sigue siendo una circunferencia","Desaparece","Se convierte en un cuadrado"],"correcta":0},{"pregunta":"Cómo se trazan a mano las elipses isométricas?","opciones":["Mediante óvalos formados por cuatro arcos de circunferencia","Con una única circunferencia","Usando una regla recta","Dibujando rectángulos"],"correcta":0},{"pregunta":"Qué ventaja tiene conocer los fundamentos manuales?","opciones":["Permite interpretar y corregir las vistas generadas por CAD","Evita usar ordenadores","Duplica el tiempo de trabajo","Sustituye toda formación"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Proyecciones centrales y perspectiva cónica', 'La proyección central, o perspectiva cónica, es el sistema de representación que imita la visión humana. Todos los rayos proyectantes parten de un mismo punto llamado centro de proyección, que corresponde al ojo del observador. Las imágenes obtenidas reproducen con realismo la sensación de profundidad y lejanía que se percibe en la realidad, y por ello se utilizan en arquitectura, escenografía, ilustración, videojuegos y cine para generar vistas que resulten intuitivas al espectador no especializado.

En el sistema cónico entran en juego varios elementos: el cuadro o plano del dibujo, la línea de tierra, la línea del horizonte, el punto principal y los puntos de fuga. Las rectas paralelas que no son paralelas al cuadro convergen en un punto de fuga situado sobre el horizonte. Según el número de puntos de fuga elegidos y su posición, se habla de perspectiva cónica frontal, de dos puntos o de tres puntos. Cada una aporta un grado distinto de dinamismo y profundidad, útil para distintos tipos de representación gráfica.

A diferencia de la axonometría, donde las medidas se conservan proporcionalmente a los ejes, la perspectiva cónica deforma longitudes y ángulos siguiendo leyes precisas de disminución con la distancia. El dibujante debe controlar el tamaño relativo de los objetos, su solape y la posición del horizonte para transmitir correctamente la tridimensionalidad. Artistas renacentistas como Brunelleschi, Alberti y Piero della Francesca codificaron las reglas matemáticas de esta representación. Hoy los programas 3D la calculan automáticamente, pero entender sus fundamentos sigue siendo imprescindible para un diseño visualmente riguroso y didácticamente convincente.',
'[{"pregunta":"Dónde parten los rayos proyectantes en una proyección central?","opciones":["De un único punto, el centro de proyección","De infinitos puntos paralelos","Del plano del dibujo","Del punto de fuga"],"correcta":0},{"pregunta":"Dónde convergen rectas paralelas no paralelas al cuadro?","opciones":["En el suelo","En un punto de fuga sobre la línea del horizonte","En el centro del papel","En el infinito absoluto"],"correcta":1},{"pregunta":"Qué tipos de cónica se citan?","opciones":["Frontal, de dos y de tres puntos","Rectangular y oblicua","Superior e inferior","Plana y esférica"],"correcta":0},{"pregunta":"Qué artistas renacentistas codificaron sus reglas?","opciones":["Brunelleschi, Alberti y Piero della Francesca","Miguel Ángel y Rafael","Donatello y Masaccio","Van Eyck y Bosch"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'BIM y modelado integral de edificios', 'BIM es el acrónimo de Building Information Modeling, una metodología de trabajo colaborativo para la gestión de proyectos de construcción basada en un modelo tridimensional centralizado que contiene toda la información del edificio. A diferencia del CAD tradicional, donde los planos son dibujos bidimensionales con información limitada, en BIM cada elemento (muro, pilar, ventana, instalación) posee parámetros geométricos, materiales, coste, fabricante y datos de mantenimiento asociados. El modelo se convierte así en una base de datos viva que acompaña al edificio durante todo su ciclo de vida.

El flujo de trabajo BIM reúne a arquitectos, ingenieros estructurales, instaladores y constructores en un mismo entorno digital. Los cambios realizados por un especialista se reflejan automáticamente en el modelo compartido, lo que reduce errores, retrabajos y conflictos entre disciplinas. Herramientas de detección de colisiones identifican, por ejemplo, un conducto que atraviesa una viga antes de llegar a la obra. Las mediciones y presupuestos se generan directamente desde el modelo, garantizando coherencia entre planos, precios y planificación temporal.

Los niveles de desarrollo, conocidos como LOD, describen la precisión con la que se detalla cada elemento, desde un volumen esquemático en fases iniciales hasta un modelo acabado con información de mantenimiento. Administraciones públicas de muchos países exigen ya BIM en obras de cierta envergadura, porque mejora la transparencia, reduce sobrecostes y facilita la explotación posterior. Las futuras líneas de investigación incluyen la integración con sensores IoT para crear gemelos digitales dinámicos del edificio, la automatización de comprobaciones normativas y la conexión con impresión 3D a gran escala en obra industrializada.',
'[{"pregunta":"Qué significa BIM?","opciones":["Building Information Modeling","Basic Industrial Method","Bidimensional Integrated Map","Building Inside Module"],"correcta":0},{"pregunta":"Qué diferencia BIM del CAD tradicional?","opciones":["Incluye información paramétrica asociada a cada elemento","No permite dibujar en 2D","Es exclusivamente arquitectónico","No usa ordenador"],"correcta":0},{"pregunta":"Qué son los LOD?","opciones":["Niveles de desarrollo que describen la precisión del modelado","Formatos de exportación gráfica","Programas de render","Unidades de longitud"],"correcta":0},{"pregunta":"Qué línea de investigación futura se cita?","opciones":["Integración con sensores IoT para gemelos digitales","Eliminación total del papel","Dibujo exclusivo a mano alzada","Uso obligatorio de lápiz rojo"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Diseño generativo', 'El diseño generativo es una metodología en la que el proyectista define objetivos, restricciones y criterios de optimización y permite que un algoritmo proponga múltiples soluciones formales. En lugar de dibujar directamente la pieza final, el diseñador establece parámetros como carga máxima, material disponible, espacio libre o coste y el software explora el espacio de soluciones posibles, evaluándolas y refinándolas iterativamente. La forma resultante emerge como respuesta al problema, y no como ocurrencia previa del autor.

Los algoritmos evolutivos, inspirados en la selección natural, son herramientas habituales. Parten de una población de diseños aleatorios que combinan, mutan y seleccionan según su rendimiento. Las redes neuronales profundas se integran cada vez más para acelerar el cálculo. El resultado suelen ser geometrías orgánicas, con celosías, estructuras de hueso o ramificaciones complejas, imposibles de concebir por un humano pero óptimas para el objetivo buscado. Estas piezas demandan, además, fabricación aditiva, ya que los procesos sustractivos tradicionales no las pueden reproducir con facilidad.

Las aplicaciones incluyen componentes aeronáuticos más ligeros, prótesis personalizadas, chasis de vehículos, mobiliario innovador y urbanismo algorítmico. Más allá del ahorro de material y peso, el diseño generativo obliga a replantear el papel del proyectista: ya no es un creador único sino un director de criterios que dialoga con la máquina. Surgen también cuestiones éticas sobre la autoría intelectual y la dependencia de herramientas que escapan al control inmediato. Aun así, su irrupción plantea una nueva frontera creativa donde arte e ingeniería convergen plenamente en proyectos de vanguardia contemporánea con gran impacto.',
'[{"pregunta":"Qué define al diseño generativo?","opciones":["El proyectista define objetivos y restricciones y el algoritmo propone soluciones","Se dibuja la pieza a mano","Se copia de un catálogo","Se usa solo papel milimetrado"],"correcta":0},{"pregunta":"Qué algoritmos se mencionan?","opciones":["Evolutivos inspirados en la selección natural","Aleatorios sin evaluación","Lineales simples","Basados en promedios"],"correcta":0},{"pregunta":"Qué tipo de fabricación requiere?","opciones":["Fabricación aditiva","Únicamente fundición","Talla manual con cincel","Molde de yeso tradicional"],"correcta":0},{"pregunta":"Qué cuestión ética se plantea?","opciones":["Autoría intelectual y dependencia de herramientas","Coste del papel","Duración del curso","Color de la tinta"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Impresión 3D y fabricación aditiva', 'La fabricación aditiva, conocida popularmente como impresión 3D, construye piezas tridimensionales depositando material capa por capa a partir de un modelo digital. A diferencia de los procesos sustractivos, que parten de un bloque y retiran material hasta lograr la forma deseada, los procesos aditivos solo utilizan el material estrictamente necesario, reduciendo residuos y permitiendo geometrías imposibles para los métodos tradicionales.

Existen numerosas tecnologías según el material y el mecanismo de unión. El modelado por deposición fundida calienta un filamento termoplástico y lo extruye sobre una base; la estereolitografía solidifica con luz ultravioleta una resina fotopolimerizable; la sinterización selectiva por láser compacta polvos metálicos o poliméricos mediante un haz láser. Cada variante ofrece ventajas distintas en precisión, resistencia, acabado y coste. Las impresoras industriales pueden trabajar con aleaciones aeronáuticas, biocompatibles o con materiales compuestos reforzados con fibra de carbono.

El flujo de trabajo implica modelar la pieza en un programa de CAD, preparar el archivo con un software de laminado que corta el modelo en capas y genera las trayectorias de impresión, y ejecutar la producción en la máquina. La impresión 3D es ya habitual en prototipado rápido, fabricación de piezas personalizadas (prótesis, ortesis, implantes dentales), herramientas de corta serie, maquetas de arquitectura y componentes aeroespaciales. Su impacto se amplía con la impresión a gran escala de estructuras de hormigón, la bioimpresión de tejidos con células vivas y la producción distribuida, que traslada la fabricación cerca del consumidor y reduce emisiones logísticas asociadas al transporte.',
'[{"pregunta":"Qué hace la fabricación aditiva?","opciones":["Depositar material capa por capa hasta construir la pieza","Recortar un bloque sólido","Inyectar plástico en moldes","Forjar metales al rojo"],"correcta":0},{"pregunta":"Qué tecnología usa resina fotopolimerizable?","opciones":["Modelado por deposición fundida","Estereolitografía","Sinterización láser","Corte por chorro de agua"],"correcta":1},{"pregunta":"Qué incluye el flujo de trabajo?","opciones":["Modelar en CAD y laminar antes de imprimir","Solo imprimir sin modelar","Fundir acero líquido","Digitalizar fotografías"],"correcta":0},{"pregunta":"Qué ventaja logística ofrece la producción distribuida?","opciones":["Reducir emisiones del transporte al acercar la fabricación al consumidor","Aumentar stocks en bodegas","Eliminar toda tecnología digital","Concentrar la producción en un único país"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Renderizado de modelos 3D', 'El renderizado es el proceso informático que convierte un modelo tridimensional y una descripción de materiales, luces y cámaras en una imagen bidimensional realista. Su objetivo es simular con la mayor fidelidad posible la forma en que la luz se propaga por una escena y llega al sensor, para producir imágenes que transmitan texturas, sombras, reflejos y transparencias como si el observador estuviera contemplando el escenario en persona. Esta herramienta es fundamental en arquitectura, diseño de producto, cine y videojuegos.

Los algoritmos de renderizado se dividen en rasterización y trazado de rayos. La rasterización, rápida y ampliamente usada en tiempo real, proyecta cada triángulo del modelo sobre la pantalla y calcula su color aproximando efectos de iluminación con atajos eficientes. El trazado de rayos sigue cada rayo de luz desde la cámara, calculando sus rebotes, refracciones y absorciones, hasta obtener una imagen fotorrealista. Variantes avanzadas como el path tracing simulan la iluminación global con precisión física notable, a costa de un coste computacional muy alto.

Los materiales se definen mediante funciones matemáticas que describen su comportamiento al reflejar la luz, incluyendo rugosidad, metalicidad, anisotropía y transmitancia. Las texturas aportan variaciones espaciales como relieves, manchas o venas. Fuentes de luz puntuales, direccionales, superficiales y ambientales completan la escena. Las tarjetas gráficas modernas aceleran por hardware el trazado de rayos, acercando el fotorrealismo al tiempo real. El renderizado sigue evolucionando con técnicas basadas en aprendizaje automático que predicen píxeles a partir de pocos datos y mejoran la eficiencia sin sacrificar mucha calidad aparente alguna.',
'[{"pregunta":"Qué convierte el renderizado?","opciones":["Un modelo 3D en una imagen 2D realista","Una fotografía en un vídeo","Un sonido en luz","Un texto en código"],"correcta":0},{"pregunta":"Qué hace el trazado de rayos?","opciones":["Sigue rayos de luz desde la cámara calculando rebotes y refracciones","Ignora las sombras","Dibuja solo siluetas","Repinta la imagen al azar"],"correcta":0},{"pregunta":"Qué describen las funciones matemáticas de los materiales?","opciones":["Cómo reflejan la luz con rugosidad, metalicidad y transmitancia","La masa total del objeto","Su nombre comercial","Su fecha de fabricación"],"correcta":0},{"pregunta":"Qué técnica actual mejora la eficiencia?","opciones":["Aprendizaje automático que predice píxeles","Pintura al óleo","Escritura manual","Solo trazado analógico"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Animación 3D', 'La animación 3D consiste en generar una secuencia de imágenes, normalmente entre 24 y 60 por segundo, que al reproducirse a alta velocidad transmitan la ilusión de movimiento. Los personajes y objetos se modelan en un programa 3D, se equipan con estructuras internas llamadas esqueletos, se asocian a la malla mediante pesos de influencia y finalmente se animan manipulando los huesos clave en poses sucesivas. El ordenador interpola las posiciones intermedias mediante curvas suaves para lograr un movimiento fluido.

Las técnicas de animación abarcan el keyframing tradicional, donde el animador define poses clave y el software rellena el resto, y la captura de movimiento, que registra los desplazamientos de actores reales mediante marcadores ópticos o trajes inerciales. La simulación física gobierna objetos como telas, fluidos, humo, pelo o multitudes, aplicando modelos dinámicos que resuelven ecuaciones de Newton en cada fotograma. El resultado añade realismo sin necesidad de animar manualmente cada elemento.

La animación 3D es hoy omnipresente en cine, series, publicidad, videojuegos, simulación médica, formación industrial y experiencias inmersivas. Permite mostrar procesos complejos, como el funcionamiento de un motor o el vuelo de un dron, de forma didáctica. En el ámbito del diseño técnico resulta útil para explicar ensamblajes de piezas, secuencias de montaje y trayectorias de mecanizado. Programas profesionales integran motores de render fotorrealista, sistemas de simulación y herramientas de edición no lineal que facilitan el trabajo colaborativo de equipos multidisciplinares distribuidos por distintos continentes con plazos ajustados y entregables diarios habitualmente.',
'[{"pregunta":"Qué frecuencia habitual tienen las imágenes en animación 3D?","opciones":["Entre 24 y 60 por segundo","Una por segundo","Una por minuto","Miles por segundo"],"correcta":0},{"pregunta":"Qué es un esqueleto en animación 3D?","opciones":["Una estructura interna asociada a la malla mediante pesos","Un material transparente","Un tipo de luz","Un archivo de imagen"],"correcta":0},{"pregunta":"Qué tipo de animación usa marcadores sobre actores reales?","opciones":["Captura de movimiento","Keyframing","Simulación estática","Rasterización plana"],"correcta":0},{"pregunta":"Qué utilidad tiene la animación en dibujo técnico?","opciones":["Explicar ensamblajes, secuencias de montaje y trayectorias","Sustituir los planos","Evitar usar CAD","Eliminar la acotación"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Realidad aumentada aplicada al diseño', 'La realidad aumentada, abreviada como RA, consiste en superponer información digital sobre la percepción del mundo físico en tiempo real. A diferencia de la realidad virtual, que sumerge al usuario en un entorno totalmente artificial, la RA añade capas de datos (imágenes, texto, modelos 3D o sonido) a la escena real observada a través de una pantalla, unas gafas transparentes o una proyección directa. Esta combinación permite interactuar con el entorno sin perder contacto visual con él.

El funcionamiento técnico requiere localizar el dispositivo y orientarlo en el espacio, reconocer superficies y objetos, y proyectar los elementos virtuales en las coordenadas adecuadas para que parezcan parte de la escena. Cámaras, giroscopios, acelerómetros, sensores LiDAR y algoritmos de visión por ordenador colaboran para lograr una alineación precisa. El renderizado debe producirse muchas veces por segundo para que el contenido virtual acompañe los movimientos del usuario sin retrasos perceptibles.

En diseño técnico y arquitectura, la realidad aumentada permite visualizar una futura instalación sobre el emplazamiento real, comprobar tolerancias en obra comparando el modelo con lo construido, o superponer instrucciones de montaje sobre una máquina para formar operarios. En ingeniería de mantenimiento, los técnicos reciben indicaciones contextuales que señalan piezas concretas y guían las tareas paso a paso. Las aplicaciones se extienden también a la educación, el comercio, el turismo y la medicina quirúrgica asistida. Los retos pendientes incluyen mejorar la ergonomía de los dispositivos, reducir su peso y garantizar la privacidad de los datos capturados y enviados por las cámaras continuamente.',
'[{"pregunta":"Qué diferencia hay entre realidad aumentada y virtual?","opciones":["La RA superpone información al mundo real, la virtual lo sustituye","Son sinónimos idénticos","La RA no usa pantallas","La virtual es más ligera y económica"],"correcta":0},{"pregunta":"Qué sensores ayudan a localizar el dispositivo?","opciones":["Cámaras, giroscopios, acelerómetros y sensores LiDAR","Solo micrófonos","Únicamente lectores RFID","Solo termómetros"],"correcta":0},{"pregunta":"Qué aplicación en diseño se cita?","opciones":["Superponer instrucciones de montaje sobre máquinas","Dibujar sobre papel","Cortar chapa a mano","Imprimir folletos"],"correcta":0},{"pregunta":"Qué reto ético se menciona?","opciones":["La privacidad de los datos capturados por las cámaras","La elección del color del casco","El tipo de tipografía","La cantidad de páginas del manual"],"correcta":0}]'::jsonb),

('dibujo-tecnico', 'bachillerato', '{2}', 'Cartografía y representación del territorio', 'La cartografía es la disciplina que se ocupa de representar gráficamente la superficie terrestre o partes de ella sobre una hoja plana. Debido a que la Tierra es aproximadamente esférica, cualquier representación plana implica necesariamente una deformación: distorsiona distancias, áreas, ángulos o formas, según el tipo de proyección empleada. Las proyecciones conformes preservan los ángulos, las equivalentes mantienen las áreas y las equidistantes conservan distancias solo en ciertas direcciones. Ninguna reúne todas las propiedades, por lo que el cartógrafo elige la proyección en función del uso previsto del mapa.

Entre las proyecciones más conocidas figuran la de Mercator, conforme y utilizada en navegación marítima por preservar los rumbos; la sinusoidal, equivalente; la de Peters, que respeta áreas; y la UTM, que divide el globo en husos para obtener mapas grandes con distorsiones pequeñas en zonas limitadas. Sobre la proyección se superponen sistemas de coordenadas que permiten localizar puntos con precisión. Las curvas de nivel representan el relieve al unir puntos con la misma altitud sobre un plano de referencia.

La cartografía moderna utiliza sistemas de información geográfica, conocidos como SIG, que gestionan capas superpuestas con datos temáticos: vegetación, usos del suelo, red hidrográfica, infraestructuras o población. Sensores remotos a bordo de satélites proporcionan imágenes actualizadas con gran resolución, y técnicas de fotogrametría reconstruyen la topografía con exactitud. Los SIG permiten analizar y cruzar datos para planificación urbana, gestión de emergencias, medio ambiente, catastro y estudios científicos, convirtiendo al mapa en una herramienta dinámica e interactiva mucho más potente que los atlas impresos convencionales usados tradicionalmente.',
'[{"pregunta":"Por qué toda proyección cartográfica implica deformación?","opciones":["Porque la Tierra es esférica y no se puede aplanar sin distorsión","Porque el papel es muy rígido","Porque los mapas se imprimen a color","Porque se dibujan con lápices"],"correcta":0},{"pregunta":"Qué preserva la proyección de Mercator?","opciones":["Las áreas totales","Los ángulos, por lo que es conforme","Solo las distancias polares","Los colores reales"],"correcta":1},{"pregunta":"Qué representan las curvas de nivel?","opciones":["Puntos con la misma altitud","Vías de tren","Ríos subterráneos","Fronteras políticas"],"correcta":0},{"pregunta":"Qué son los SIG?","opciones":["Sistemas de información geográfica con capas temáticas","Sistemas industriales de gas","Softwares de grafología","Sistemas inerciales de giro"],"correcta":0}]'::jsonb);

-- =====================================================
-- EDUCACION FISICA (12)
-- =====================================================

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('ed-fisica', 'bachillerato', '{2}', 'Metabolismo lipídico durante el ejercicio', 'Los lípidos representan la mayor reserva energética del organismo. Un adulto sano almacena en el tejido adiposo unos 100.000 kilocalorías en forma de triglicéridos, cantidad suficiente para sostener semanas de actividad moderada. Durante el ejercicio, los triglicéridos se hidrolizan en ácidos grasos libres y glicerol; los ácidos grasos viajan unidos a albúmina hasta el músculo activo, entran en la mitocondria mediante el sistema carnitina y se oxidan en la beta-oxidación, generando gran cantidad de ATP.

La proporción de lípidos utilizados depende de la intensidad del esfuerzo. A intensidades bajas y moderadas, en torno al 50-65 por ciento del consumo máximo de oxígeno, el uso de grasas alcanza su máximo absoluto, fenómeno conocido como fat max. Al elevar la intensidad, el organismo prioriza los hidratos de carbono porque permiten producir energía más rápidamente. Durante ejercicios muy prolongados, aunque la intensidad aumente, los lípidos siguen contribuyendo porque las reservas de glucógeno se agotan antes que las de grasa.

Los deportes de resistencia, como el ciclismo, el maratón o el triatlón de larga distancia, dependen de una buena capacidad oxidativa lipídica. El entrenamiento induce adaptaciones que aumentan la densidad mitocondrial, el número de enzimas beta-oxidativas y la capilarización muscular, mejorando la utilización de grasas. Estrategias como entrenar con reservas bajas de glucógeno o emplear dietas cetogénicas pretenden potenciar este metabolismo, aunque las evidencias aún son contradictorias respecto al rendimiento real en competición. Individualizar la nutrición resulta esencial en deportes con muy alta demanda energética sostenida y prolongada durante horas en competición.',
'[{"pregunta":"Qué cantidad aproximada de energía almacena el tejido adiposo?","opciones":["100 kcal","100.000 kcal","1.000 kcal","10 millones de kcal"],"correcta":1},{"pregunta":"Qué sistema transporta los ácidos grasos al interior mitocondrial?","opciones":["Carnitina","Lactato deshidrogenasa","Hemoglobina","Creatina"],"correcta":0},{"pregunta":"Qué es el fat max?","opciones":["La intensidad a la que la oxidación de grasas alcanza su máximo","El peso máximo del deportista","Un suplemento dietético","La temperatura corporal máxima"],"correcta":0},{"pregunta":"Qué adaptaciones induce el entrenamiento de resistencia?","opciones":["Mayor densidad mitocondrial y capilarización","Menor número de mitocondrias","Reducción de enzimas oxidativas","Atrofia muscular rápida"],"correcta":0}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Entrenamiento concurrente', 'El entrenamiento concurrente combina en un mismo programa el trabajo de fuerza y el de resistencia aeróbica. Un ejemplo típico es el de un deportista que alterna series de musculación con sesiones de carrera continua en distintas fases de la semana. Aunque ambas capacidades son compatibles y muchos deportes las requieren simultáneamente, la investigación ha demostrado que su combinación puede interferir en las adaptaciones específicas si no se planifica con cuidado, un fenómeno bautizado como efecto interferencia.

El origen fisiológico de esa interferencia se sitúa en las vías moleculares activadas por cada tipo de estímulo. La fuerza activa la vía mTOR, que promueve síntesis proteica e hipertrofia; la resistencia activa la vía AMPK, que favorece biogénesis mitocondrial y oxidación lipídica. La activación simultánea de ambas rutas puede atenuar las ganancias de fuerza, especialmente cuando los entrenamientos se encadenan sin descanso suficiente o cuando el volumen aeróbico es muy elevado. Las ganancias de resistencia se ven mucho menos afectadas.

Para minimizar el problema, se recomienda separar las sesiones de fuerza y resistencia por al menos 6 horas, o incluso realizarlas en días distintos cuando se busquen máximas ganancias de hipertrofia. Otra estrategia es priorizar la capacidad limitante en cada fase del mesociclo. En deportes de equipo y disciplinas de resistencia, el entrenamiento concurrente sigue siendo imprescindible para lograr un atleta completo, capaz de soportar esfuerzos prolongados y producir potencia explosiva cuando la situación lo requiere. La periodización inteligente permite conciliar ambas adaptaciones sin sacrificar el rendimiento competitivo global del deportista profesional actual moderno.',
'[{"pregunta":"Qué combina el entrenamiento concurrente?","opciones":["Fuerza y resistencia aeróbica","Solo estiramientos","Arte y cocina","Baloncesto y ajedrez"],"correcta":0},{"pregunta":"Qué vía molecular promueve la fuerza?","opciones":["mTOR","AMPK exclusivamente","Lipogénesis","Glucólisis"],"correcta":0},{"pregunta":"Qué capacidad se ve más afectada por el efecto interferencia?","opciones":["Fuerza y ganancias de hipertrofia","La resistencia aeróbica","La flexibilidad","La propiocepción"],"correcta":0},{"pregunta":"Qué estrategia reduce la interferencia?","opciones":["Separar sesiones por al menos 6 horas o hacerlas en días distintos","Entrenar sin descanso","Duplicar el volumen","Eliminar la fuerza"],"correcta":0}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Métodos de recuperación postesfuerzo', 'La recuperación es una parte tan importante del proceso de entrenamiento como la propia sesión. Durante el esfuerzo se producen microlesiones musculares, depleción de glucógeno, desequilibrios electrolíticos y fatiga del sistema nervioso central. Un retorno adecuado al estado basal permite asimilar el estímulo, adaptar el organismo y prevenir el sobreentrenamiento. Las estrategias de recuperación activa y pasiva buscan acelerar estos procesos y optimizar el rendimiento en la siguiente sesión.

Las técnicas pasivas incluyen el descanso nocturno, de importancia capital, pues durante el sueño profundo se liberan hormonas anabólicas como la del crecimiento y se consolidan adaptaciones neurales. La hidroterapia con baños de contraste alterna inmersión en agua fría y templada para estimular la circulación periférica. La crioterapia con agua helada o cámaras de aire frío reduce la inflamación aguda, aunque puede atenuar algunas adaptaciones si se abusa de ella tras entrenamientos de fuerza. Los masajes descargan tensiones musculares y mejoran el bienestar subjetivo.

Las técnicas activas consisten en realizar ejercicio de baja intensidad tras el esfuerzo para eliminar lactato y mantener el flujo sanguíneo. Dispositivos de presoterapia, rodillos de espuma y electroestimulación complementan el repertorio. La nutrición desempeña un papel central: la ingesta de carbohidratos y proteínas en la ventana postesfuerzo acelera la resíntesis de glucógeno y la reparación muscular. La hidratación repone los líquidos perdidos con el sudor. Cada deportista debe individualizar su protocolo según el tipo de esfuerzo y las demandas de su calendario competitivo personal propio e individual único particular.',
'[{"pregunta":"Por qué el descanso nocturno es fundamental?","opciones":["Durante el sueño profundo se liberan hormonas anabólicas","Porque se ingieren carbohidratos","Porque se entrena mejor","Porque se producen lesiones"],"correcta":0},{"pregunta":"Qué efecto puede tener abusar de la crioterapia tras fuerza?","opciones":["Atenuar algunas adaptaciones","Aumentar todas las ganancias","No influir","Acelerar infinitamente"],"correcta":0},{"pregunta":"Qué son las técnicas activas?","opciones":["Ejercicio de baja intensidad tras el esfuerzo","Sueño prolongado","Baños de contraste","Masaje profundo"],"correcta":0},{"pregunta":"Qué aporta la nutrición en la ventana postesfuerzo?","opciones":["Resíntesis de glucógeno y reparación muscular","Más fatiga","Pérdida de electrolitos","Aumento de lactato"],"correcta":0}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Deporte paralímpico e inclusión', 'El deporte paralímpico es el movimiento deportivo internacional para personas con discapacidad física, visual o intelectual. Su origen se remonta a los Juegos de Stoke Mandeville, creados en 1948 por el neurólogo Ludwig Guttmann como parte de la rehabilitación de veteranos de guerra con lesiones medulares. Desde entonces el movimiento ha crecido hasta convertirse en el segundo mayor evento deportivo del planeta, solo por detrás de los Juegos Olímpicos tradicionales, con los que comparten sedes desde 1988.

Las pruebas están organizadas por categorías funcionales que agrupan a deportistas con niveles de afectación similares, de modo que compitan en igualdad de condiciones. Los sistemas de clasificación son complejos y están en constante revisión por comisiones de expertos médicos y deportivos. Algunas disciplinas, como el baloncesto en silla de ruedas, el goalball para ciegos o el boccia para personas con parálisis cerebral, se han desarrollado específicamente para el ámbito paralímpico. Otras adaptan las reglas de deportes convencionales para permitir la participación equitativa.

El impacto del paralimpismo va mucho más allá de las medallas. Visibiliza la capacidad de las personas con discapacidad, normaliza su presencia en los medios de comunicación y empuja a las administraciones a mejorar la accesibilidad de instalaciones deportivas. En el ámbito educativo, las actividades físicas inclusivas permiten a todo el alumnado compartir experiencias deportivas independientemente de sus circunstancias. La tecnología colabora con prótesis, sillas de carreras y equipamientos adaptados, aunque también plantea debates sobre límites éticos cuando los dispositivos amplían capacidades humanas más allá de lo natural, lo que suscita interesantes polémicas.',
'[{"pregunta":"Dónde se originó el deporte paralímpico?","opciones":["En los Juegos de Stoke Mandeville creados por Ludwig Guttmann en 1948","En Roma en 1960","En Barcelona en 1992","En Atenas en 1896"],"correcta":0},{"pregunta":"Cómo se organizan las pruebas?","opciones":["Por edad cronológica","Por categorías funcionales con niveles similares","Por peso corporal exclusivamente","Al azar"],"correcta":1},{"pregunta":"Qué disciplina se desarrolló específicamente para personas ciegas?","opciones":["Baloncesto en silla de ruedas","Goalball","Boccia","Tenis de mesa"],"correcta":1},{"pregunta":"Qué impacto social positivo se destaca?","opciones":["Visibiliza capacidades y mejora accesibilidad","Reduce el número de escuelas","Aísla a las personas","Encarece las competiciones olímpicas"],"correcta":0}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Gamificación del deporte y la actividad física', 'La gamificación aplicada a la actividad física consiste en incorporar mecánicas propias de los juegos (retos, puntos, niveles, recompensas, rankings) a contextos que no son un juego, con el objetivo de aumentar la motivación, la participación y la persistencia. Las aplicaciones móviles que registran pasos, distancia o calorías convierten el ejercicio cotidiano en una experiencia medible y comparable. Plataformas virtuales permiten correr o pedalear rutas reales en un entorno digital compartido, donde los usuarios compiten o colaboran con otros en tiempo real.

Desde la perspectiva psicológica, la gamificación aprovecha mecanismos del sistema de recompensa cerebral. Cada logro libera pequeñas cantidades de dopamina que refuerzan la conducta y aumentan la probabilidad de repetirla. Insignias, retos semanales y celebraciones virtuales aportan feedback inmediato, algo que los programas de entrenamiento tradicionales, con resultados a medio plazo, no suelen ofrecer. Cuando se combinan con objetivos personales bien definidos y supervisión técnica, los elementos gamificados mejoran la adherencia al ejercicio, especialmente en poblaciones sedentarias.

En educación física escolar, la gamificación sirve para dinamizar sesiones a través de circuitos temáticos, narrativas envolventes y retos por equipos. Bien diseñada, fomenta el aprendizaje cooperativo, la diversidad de roles y la inclusión del alumnado con menor motivación hacia el movimiento. Sin embargo, presenta riesgos si los incentivos externos eclipsan el placer intrínseco de la actividad o si las comparaciones constantes generan ansiedad. La clave está en usar estas mecánicas como puente hacia hábitos saludables autónomos, y no como un fin sustitutivo del valor educativo y formativo del propio deporte.',
'[{"pregunta":"Qué es la gamificación de la actividad física?","opciones":["Incorporar mecánicas de juego (retos, puntos, niveles) al ejercicio","Reducir el deporte a ver partidos","Jugar videojuegos sin moverse","Eliminar reglas deportivas"],"correcta":0},{"pregunta":"Qué sistema cerebral aprovecha?","opciones":["El sistema de recompensa con dopamina","Solo el cerebelo","El sistema digestivo","El sistema endocrino exclusivamente"],"correcta":0},{"pregunta":"Qué beneficio destaca en poblaciones sedentarias?","opciones":["Mejora la adherencia al ejercicio","Elimina la necesidad de moverse","Genera fatiga inmediata","Reduce la motivación"],"correcta":0},{"pregunta":"Qué riesgo se menciona?","opciones":["Que los incentivos externos eclipsen el placer intrínseco","Prohibir los deportes escolares","Desaparecer la dopamina","Reducir la inclusión siempre"],"correcta":0}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Neuroeducación física', 'La neuroeducación física aplica hallazgos de las neurociencias cognitivas al diseño de actividades motrices en contextos educativos. Parte del hecho de que el movimiento y el cerebro están íntimamente ligados: el ejercicio mejora la neurogénesis hipocampal, aumenta la producción de factores neurotróficos como BDNF y favorece las funciones ejecutivas. Esta conexión justifica que las sesiones de educación física no solo repercutan en la salud física, sino también en la atención, la memoria y el rendimiento académico general del alumnado.

Estudios recientes demuestran que alternar periodos de actividad moderada con momentos de trabajo cognitivo optimiza el aprendizaje. El ejercicio aeróbico regular mejora la concentración y reduce los síntomas de trastornos como el TDAH. Las actividades que combinan coordinación, equilibrio y toma de decisiones, como los deportes abiertos o las situaciones motrices variables, exigen procesamiento multisensorial complejo y estimulan áreas cerebrales asociadas al aprendizaje. Los juegos cooperativos activan la empatía, la regulación emocional y la comunicación interpersonal.

Aplicar la neuroeducación física en el aula implica replantear las sesiones: incorporar movimiento al aprendizaje de contenidos académicos, diseñar tareas que supongan un desafío cognitivo, dosificar intensidad y descanso, y atender a la variabilidad individual. El ambiente emocional del grupo resulta decisivo: experiencias positivas reforzadas por la liberación de dopamina consolidan el aprendizaje motor. El objetivo no es convertir la educación física en una clase teórica, sino reconocer y potenciar su potencial como herramienta integral de desarrollo que trasciende lo puramente físico y alcanza la dimensión intelectual, emocional y social del alumnado adolescente.',
'[{"pregunta":"Qué factor neurotrófico se cita?","opciones":["BDNF","Insulina","Melatonina","Testosterona"],"correcta":0},{"pregunta":"Qué beneficios académicos aporta el ejercicio regular?","opciones":["Mejora atención, memoria y rendimiento","Ninguno significativo","Solo aumenta la fatiga","Reduce las funciones ejecutivas"],"correcta":0},{"pregunta":"Qué tipo de actividades estimulan áreas asociadas al aprendizaje?","opciones":["Deportes abiertos con toma de decisiones","Simple estiramiento pasivo","Descanso absoluto","Lectura sentada"],"correcta":0},{"pregunta":"Cuál es el objetivo de la neuroeducación física?","opciones":["Convertir EF en clase teórica","Potenciar el desarrollo integral físico, emocional, intelectual y social","Eliminar el movimiento","Reducir las horas de clase"],"correcta":1}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Género y deporte', 'La relación entre género y deporte ha sido históricamente desigual. Durante la mayor parte del siglo XX, mujeres y niñas enfrentaron exclusiones explícitas en numerosas disciplinas, justificadas por prejuicios sobre su fisiología o por normas sociales restrictivas. En los Juegos Olímpicos modernos de 1896 no participó ninguna mujer, y muchas pruebas como el maratón femenino o el fútbol femenino tardaron décadas en ser admitidas oficialmente en programas internacionales con todas las garantías competitivas.

Hoy la participación femenina ha aumentado enormemente. Los Juegos de París 2024 alcanzaron la paridad total entre atletas masculinos y femeninos por primera vez en la historia. Sin embargo, persisten desigualdades en la visibilidad mediática, en los patrocinios y en los premios económicos. Los estudios muestran que los medios de comunicación dedican una fracción muy inferior de su tiempo y espacio al deporte femenino, y que los techos salariales siguen siendo marcadamente más bajos en muchas disciplinas profesionales de ámbito internacional muy populares.

El debate contemporáneo aborda además cuestiones complejas como la integración de personas trans, la protección de categorías por sexo biológico y las hiperandrogenismos naturales. Instituciones como el COI han aprobado marcos generales, pero cada federación internacional dicta reglas propias y a veces contradictorias. Promover la igualdad en el deporte implica políticas activas de visibilidad, formación en perspectiva de género, programas de apoyo a entrenadoras y directivas, prevención del acoso y medidas que combatan los estereotipos desde la educación física escolar temprana hasta el alto rendimiento, como proceso formativo continuo imprescindible.',
'[{"pregunta":"Qué ocurrió en los Juegos de París 2024?","opciones":["Se alcanzó la paridad total entre atletas masculinos y femeninos","Se prohibió la participación femenina","Solo compitieron hombres","Solo se hicieron en invierno"],"correcta":0},{"pregunta":"Qué desigualdades persisten?","opciones":["Visibilidad mediática, patrocinios y premios","Ninguna","Participación olímpica","Número de disciplinas inicial"],"correcta":0},{"pregunta":"Qué cuestión compleja se debate?","opciones":["La integración de personas trans y categorías por sexo","La abolición de los Juegos","Los colores de los dorsales","La duración del himno"],"correcta":0},{"pregunta":"Qué propone el texto para la igualdad?","opciones":["Políticas activas de visibilidad, formación y prevención del acoso","Eliminar el deporte femenino","Abolir el deporte masculino","Unificar toda competición sin categorías"],"correcta":0}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Economía del deporte', 'El deporte es hoy una industria global que mueve cientos de miles de millones de euros y genera empleo en múltiples sectores: organización de eventos, clubes profesionales, medios de comunicación, fabricación de equipamiento, turismo, patrocinios y apuestas deportivas. Los derechos de retransmisión televisiva constituyen una de sus principales fuentes de ingresos para grandes ligas, junto con los contratos publicitarios, la venta de entradas y el merchandising. Eventos como los Juegos Olímpicos o la final de la Champions League alcanzan audiencias mundiales multimillonarias.

Desde el punto de vista macroeconómico, el deporte contribuye al producto interior bruto, al empleo y a la imagen exterior de los países. Las ciudades que albergan grandes citas deportivas persiguen efectos multiplicadores: atracción de turistas, renovación de infraestructuras y proyección internacional. Sin embargo, los estudios académicos han cuestionado los balances demasiado optimistas, mostrando que muchos megaeventos dejan un legado de instalaciones infrautilizadas, endeudamiento y efectos limitados sobre la economía local a medio plazo sostenible.

En el plano microeconómico, los clubes deportivos son empresas con modelos de negocio complejos. Dependen de los resultados deportivos, cuyos ingresos son difíciles de prever, y de un mercado laboral muy concentrado donde unas pocas estrellas capturan una parte importante de los salarios totales. Las regulaciones financieras, como el fair play financiero de la UEFA, intentan evitar que los clubes gasten más de lo que ingresan y mantener una competición equilibrada. Nuevos fenómenos como los esports, el fútbol femenino profesional o la financiación mediante criptoactivos amplían y transforman este ecosistema económico permanentemente diverso.',
'[{"pregunta":"Cuál es una de las principales fuentes de ingresos del deporte profesional?","opciones":["Derechos de retransmisión televisiva","Venta de libros","Impuestos estatales","Donaciones anónimas"],"correcta":0},{"pregunta":"Qué advierten los estudios sobre los megaeventos deportivos?","opciones":["Sus beneficios suelen ser exagerados y pueden dejar infraestructuras infrautilizadas","Siempre enriquecen a la ciudad","No tienen costes","Eliminan la deuda municipal"],"correcta":0},{"pregunta":"Qué es el fair play financiero?","opciones":["Una regulación para que los clubes no gasten más de lo que ingresan","Una norma sobre faltas en el campo","Un sistema de puntuación","Un torneo amistoso"],"correcta":0},{"pregunta":"Qué fenómenos transforman el ecosistema económico del deporte?","opciones":["Esports, deporte femenino profesional y criptoactivos","La eliminación de los patrocinios","La vuelta al amateurismo total","La prohibición de la publicidad"],"correcta":0}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Dopaje genético', 'El dopaje genético consiste en la manipulación intencionada del material genético de un deportista, o del funcionamiento de determinados genes, para mejorar su rendimiento físico. A diferencia del dopaje farmacológico clásico, no introduce sustancias externas detectables de manera directa, sino que puede modificar de forma duradera la expresión de genes relacionados con la producción de eritropoyetina, factores de crecimiento, miostatina o angiogénesis. El resultado teórico es un aumento de glóbulos rojos, masa muscular o capilarización, sin necesidad de inyecciones repetidas.

La idea surgió a comienzos del siglo XXI, cuando los avances en terapia génica mostraron que algunas enfermedades hereditarias podían tratarse insertando copias funcionales de un gen defectuoso. La Agencia Mundial Antidopaje, AMA, incluyó el dopaje genético en su lista de prohibiciones en 2003, antes de que existieran pruebas confirmadas de su uso en competición. Los riesgos son considerables: la inserción descontrolada de material genético puede activar oncogenes, provocar respuestas inmunitarias graves o efectos secundarios impredecibles a largo plazo.

Detectar el dopaje genético es un reto técnico enorme. Se investigan métodos basados en la secuenciación profunda de sangre, la búsqueda de ADN viral característico de los vectores de terapia génica y la medición de perfiles anómalos de expresión de ARN. La lucha contra esta forma de dopaje exige una colaboración internacional, inversión en investigación y concienciación ética. El deporte se enfrenta a la paradoja de que tecnologías con enorme potencial médico podrían poner en peligro la integridad de la competición, la salud de los deportistas y los valores formativos que el deporte pretende transmitir a futuras generaciones jóvenes.',
'[{"pregunta":"Qué es el dopaje genético?","opciones":["Manipulación del material genético o la expresión de genes para mejorar el rendimiento","Inyección de vitaminas","Dieta rica en proteínas","Uso de geles musculares"],"correcta":0},{"pregunta":"Cuándo prohibió la AMA el dopaje genético?","opciones":["En 2003","En 1988","En 2020","Nunca lo ha prohibido"],"correcta":0},{"pregunta":"Qué riesgo médico se cita?","opciones":["Activación de oncogenes y respuestas inmunitarias graves","Aumento inmediato de fuerza sin efectos","Rejuvenecimiento eterno","Ningún efecto secundario"],"correcta":0},{"pregunta":"Por qué es difícil detectarlo?","opciones":["No introduce sustancias externas fácilmente rastreables","Porque no existe","Porque las pruebas son baratas","Porque se ve a simple vista"],"correcta":0}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Inclusión en educación física', 'La inclusión en educación física implica diseñar propuestas motrices que permitan a todo el alumnado participar con sentido, independientemente de sus características personales, sus capacidades o su contexto. Supera el concepto de integración, que buscaba adaptar al individuo al programa existente, para plantear justo lo contrario: es el programa el que debe adaptarse a la diversidad del grupo. Este planteamiento se alinea con la perspectiva del Diseño Universal para el Aprendizaje, centrada en ofrecer múltiples formas de representación, acción y compromiso.

En la práctica, la educación física inclusiva exige al docente conocer profundamente al alumnado. Las unidades didácticas se plantean con tareas abiertas que permiten distintos niveles de resolución, con reglas modificables y con materiales variados. Los agrupamientos heterogéneos fomentan relaciones constructivas entre compañeros con habilidades diferentes. Las adaptaciones pueden ser organizativas, metodológicas o de acceso, y deben revisarse continuamente para responder a las necesidades del grupo. La evaluación se centra en procesos y esfuerzos, no solo en rendimientos finales.

Los beneficios de un enfoque inclusivo trascienden lo motor. Promueven actitudes de respeto, empatía y cooperación que se proyectan al conjunto de la vida escolar. Los estudiantes aprenden a valorar la diversidad como una riqueza y no como un obstáculo, y desarrollan una autoimagen positiva al sentirse parte real de la clase. Las barreras persistentes incluyen la formación específica del profesorado, la accesibilidad de instalaciones y materiales, y los estereotipos culturales todavía presentes. Una educación física verdaderamente inclusiva constituye un derecho del alumnado y un compromiso profesional exigible a todo el sistema educativo democrático plural contemporáneo.',
'[{"pregunta":"Qué diferencia hay entre inclusión e integración?","opciones":["Inclusión adapta el programa al alumnado; integración adaptaba al alumnado al programa","Son términos sinónimos","La inclusión excluye a alumnos","La integración es más moderna"],"correcta":0},{"pregunta":"Qué metodología se alinea con la inclusión?","opciones":["El Diseño Universal para el Aprendizaje","La enseñanza dirigida por mando directo","La exclusión funcional","El libro de texto único"],"correcta":0},{"pregunta":"Qué criterios guían la evaluación inclusiva?","opciones":["Procesos y esfuerzos, no solo rendimientos finales","Solo la marca cronometrada","El peso corporal","El color del uniforme"],"correcta":0},{"pregunta":"Qué barrera persistente se menciona?","opciones":["Formación del profesorado y accesibilidad de instalaciones","Demasiados materiales","Falta de alumnos","Exceso de horas lectivas"],"correcta":0}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Entrenamiento en altitud', 'El entrenamiento en altitud es una estrategia utilizada por deportistas de resistencia para mejorar su rendimiento aprovechando la menor presión parcial de oxígeno característica de las zonas elevadas. Al respirar un aire con igual porcentaje de oxígeno pero menor presión, los tejidos reciben menos O2 por respiración, lo que obliga al organismo a activar respuestas adaptativas. El riñón libera más eritropoyetina y la médula ósea produce más glóbulos rojos, lo que aumenta la capacidad de transporte de oxígeno cuando el atleta regresa al nivel del mar.

Existen varios modelos metodológicos. El método vivir y entrenar en altura expone al deportista a todas las sesiones en alturas elevadas, pero reduce la intensidad absoluta, lo que puede comprometer adaptaciones neuromusculares. El método vivir alto y entrenar bajo combina residencia en altura con sesiones intensivas a menor cota, permitiendo mantener la calidad del entrenamiento. Las cámaras hipóxicas y las tiendas de simulación reproducen artificialmente condiciones de altura en cualquier lugar, facilitando la planificación.

Los efectos no son universales. Algunos deportistas responden con grandes aumentos de glóbulos rojos, otros apenas perciben cambios. La altitud también puede provocar molestias como cefalea, insomnio, deshidratación o mal de altura, por lo que exige un proceso de aclimatación gradual y supervisión médica. El dopaje sanguíneo y la administración exógena de eritropoyetina han aprovechado durante años el mismo mecanismo biológico, creando una frontera ética difusa entre la adaptación natural y la manipulación ilícita. El monitoreo del pasaporte biológico busca detectar estas irregularidades con rigor científico contrastado en laboratorios acreditados plenamente.',
'[{"pregunta":"Qué adaptación clave produce el entrenamiento en altitud?","opciones":["Aumento de glóbulos rojos por liberación de eritropoyetina","Pérdida de masa muscular","Reducción del oxígeno pulmonar","Eliminación del lactato cero"],"correcta":0},{"pregunta":"Qué ventaja tiene vivir alto y entrenar bajo?","opciones":["Mantener la intensidad del entrenamiento mientras se vive en altura","Dormir peor","Entrenar sin descanso","Reducir la resistencia"],"correcta":0},{"pregunta":"Qué efectos adversos se citan?","opciones":["Cefalea, insomnio, deshidratación y mal de altura","Ganancia automática de fuerza","Ausencia de fatiga","Mejor digestión"],"correcta":0},{"pregunta":"Qué detecta el pasaporte biológico?","opciones":["Irregularidades sanguíneas compatibles con dopaje","El peso corporal diario","El consumo calórico","El nivel educativo del atleta"],"correcta":0}]'::jsonb),

('ed-fisica', 'bachillerato', '{2}', 'Descanso activo y prevención de lesiones', 'El descanso activo consiste en realizar actividades físicas de baja intensidad durante los periodos destinados al reposo deportivo, en lugar de permanecer totalmente inactivo. Su objetivo es facilitar la recuperación sin comprometer las adaptaciones obtenidas con el entrenamiento. Paseos suaves, natación lenta, yoga, ciclismo tranquilo o movilidad articular son ejemplos comunes. A diferencia del reposo absoluto, mantiene la circulación sanguínea activa, favorece la eliminación de metabolitos y reduce la rigidez muscular.

Desde el punto de vista fisiológico, el descanso activo promueve la vascularización en los tejidos trabajados, mejora el drenaje linfático y estimula la reparación del daño muscular inducido por el ejercicio. La liberación de endorfinas y la regulación del sistema nervioso autónomo contribuyen a un estado de bienestar general que ayuda a asimilar la carga del microciclo. Algunas investigaciones sugieren que alternar sesiones exigentes con sesiones suaves puede reducir el riesgo de lesiones por sobreuso, muy comunes en deportistas que entrenan de forma muy monótona.

La prevención de lesiones es un ámbito donde el descanso activo se integra con otras estrategias: calentamiento adecuado, entrenamiento de fuerza específico, mejora de la movilidad articular, control de la técnica, monitoreo de la carga externa e interna, y respeto escrupuloso al sueño. Los programas FIFA 11+, el protocolo Nordic para isquiotibiales o las rutinas de estabilidad del core son ejemplos avalados por la evidencia. El objetivo final no es evitar todo riesgo, imposible en el deporte competitivo, sino reducir la probabilidad de lesión y garantizar una respuesta ante cualquier percance competitivo y contratiempo deportivo adecuadamente.',
'[{"pregunta":"En qué consiste el descanso activo?","opciones":["Realizar actividades físicas de baja intensidad durante el reposo","Permanecer tumbado sin moverse","Entrenar a máxima intensidad","Comer más calorías"],"correcta":0},{"pregunta":"Qué beneficios fisiológicos aporta?","opciones":["Mejora vascularización y drenaje linfático","Aumenta el daño muscular","Produce mayor fatiga que el entrenamiento","Disminuye la circulación"],"correcta":0},{"pregunta":"Qué programa cita el texto para prevención de lesiones?","opciones":["FIFA 11+","Marathon Ready","Gym Plus","Winter Safe"],"correcta":0},{"pregunta":"Cuál es el objetivo final de la prevención según el texto?","opciones":["Eliminar todo riesgo","Reducir la probabilidad de lesión y garantizar buenas respuestas","Entrenar menos","Evitar el calentamiento"],"correcta":1}]'::jsonb);

